import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0])

    # Precompute teleport lists
    teleport_lists = [[[] for _ in range(n)] for _ in range(m)]
    for i in range(m):
        for j in range(n):
            val = grid[i][j]
            for x in range(m):
                for y in range(n):
                    if grid[x][y] <= val:
                        teleport_lists[i][j].append((x, y))

    INF = float('inf')
    dist = [[[INF] * (k + 1) for _ in range(n)] for _ in range(m)]
    dist[0][0][0] = 0
    heap = [(0, 0, 0, 0)]

    while heap:
        cost, i, j, k_used = heapq.heappop(heap)
        if i == m - 1 and j == n - 1:
            return cost
        if cost > dist[i][j][k_used]:
            continue

        # Regular moves: right and down
        if j + 1 < n:
            new_i, new_j = i, j + 1
            new_cost = cost + grid[new_i][new_j]
            if new_cost < dist[new_i][new_j][k_used]:
                dist[new_i][new_j][k_used] = new_cost
                heapq.heappush(heap, (new_cost, new_i, new_j, k_used))
        if i + 1 < m:
            new_i, new_j = i + 1, j
            new_cost = cost + grid[new_i][new_j]
            if new_cost < dist[new_i][new_j][k_used]:
                dist[new_i][new_j][k_used] = new_cost
                heapq.heappush(heap, (new_cost, new_i, new_j, k_used))

        # Teleport moves
        if k_used < k:
            for (x, y) in teleport_lists[i][j]:
                new_k = k_used + 1
                if cost < dist[x][y][new_k]:
                    dist[x][y][new_k] = cost
                    heapq.heappush(heap, (cost, x, y, new_k))

    return dist[m-1][n-1][0]
